import json
import ast
import pandas as pd

# Get file paths
path_businesses = locals()['var_function-call-1762609296451302444']
path_reviews = locals()['var_function-call-1762609296451304817']

# Load data
with open(path_businesses, 'r') as f:
    businesses = json.load(f)

with open(path_reviews, 'r') as f:
    reviews = json.load(f)

# Create DataFrame for reviews
df_reviews = pd.DataFrame(reviews)
df_reviews['rating'] = pd.to_numeric(df_reviews['rating'], errors='coerce')

# Calculate average rating per business
avg_ratings = df_reviews.groupby('gmap_id')['rating'].mean().to_dict()

# Helper function to parse time
def to_24hr(time_str):
    if not time_str:
        return None
    time_str = time_str.strip()
    is_pm = 'PM' in time_str
    is_am = 'AM' in time_str

    # Remove AM/PM
    t = time_str.replace('PM', '').replace('AM', '').strip()

    parts = t.split(':')
    try:
        h = int(parts[0])
        m = int(parts[1]) if len(parts) > 1 else 0
    except ValueError:
        return None

    if is_pm and h != 12:
        h += 12
    if is_am and h == 12:
        h = 0

    return h * 60 + m

def is_open_after_6pm(hours_str):
    if not hours_str or hours_str == 'None':
        return False

    try:
        hours_list = ast.literal_eval(hours_str)
    except:
        return False

    weekdays = {'Monday', 'Tuesday', 'Wednesday', 'Thursday', 'Friday'}

    # Check if any weekday meets condition
    for day_info in hours_list:
        if len(day_info) != 2:
            continue
        day, time_range = day_info

        if day in weekdays:
            if time_range == "Open 24 hours":
                return True
            if time_range == "Closed":
                continue

            # Split range
            if '\u2013' in time_range:
                parts = time_range.split('\u2013')
            elif '-' in time_range:
                parts = time_range.split('-')
            else:
                continue

            if len(parts) != 2:
                continue

            end_time = parts[1]

            # Parse end time
            minutes_from_midnight = to_24hr(end_time)

            if minutes_from_midnight is None:
                continue

            # 6:00 PM = 1080
            # Condition: Closing time > 18:00

            is_am = 'AM' in end_time
            is_pm = 'PM' in end_time

            val = minutes_from_midnight

            if is_pm:
                if val > 1080:
                    return True
            elif is_am:
                # If closing in AM (next day), it's definitely after 6PM (previous day).
                # Unless it's morning shift ending before noon.
                # Check start time to be sure.
                start_time = parts[0]
                start_val = to_24hr(start_time)
                if start_val is not None:
                    if val < start_val: # Crosses midnight
                        return True
                    else:
                        # Same day. e.g. 6AM-11AM. End=11AM (660) < 1080. False.
                        if val > 1080:
                            return True

    return False

filtered_businesses = []
for b in businesses:
    if b['gmap_id'] in avg_ratings:
        if is_open_after_6pm(b['hours']):
            b['avg_rating'] = avg_ratings[b['gmap_id']]
            filtered_businesses.append(b)

# Sort by avg_rating desc
# Also sort by number of reviews or name for stability? 
filtered_businesses.sort(key=lambda x: (x['avg_rating'], x['name']), reverse=True)

top_5 = filtered_businesses[:5]

result = []
for b in top_5:
    result.append({
        "name": b['name'],
        "hours": b['hours'],
        "average_rating": b['avg_rating']
    })

print("__RESULT__:")
print(json.dumps(result))

